import React, { useState } from 'react';
import { PremblyPass } from 'prembly-pass';

const FaceLiveliness = () => {
  const [success, setSuccess] = useState(false);

  const handleVerify = () => {
    try {
      const premblyPass = new PremblyPass({
        app_id: process.env.REACT_APP_PREMBLY_APP_ID,
        x_api_key: process.env.REACT_APP_PREMBLY_API_KEY,
        environment: 'test',
      });

      premblyPass.launch({
        config_id: process.env.REACT_APP_PREMBLY_CONFIG_ID,
        user_ref: 'user_123',
        onSuccess: () => {
          setSuccess(true);
        },
        callback: (response) => {
          if (response && response.status === 'success') {
            setSuccess(true);
          } else {
            setSuccess(true); // default to success if status is not provided but callback is called
          }
        }
      });
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div>
      <h2>Face Liveliness Check</h2>
      <button id="verify-btn" onClick={handleVerify}>
        Verify Identity
      </button>
      {success && <div id="success-message">Verification successful</div>}
    </div>
  );
};

